    pub fn default() -> WasmServerConfig {
        kreuzberg::ServerConfig::default().into()
    }

    /// Get the server listen address (host:port).
    ///
    /// # Example
    ///
    /// ```rust
    /// use kreuzberg::core::ServerConfig;
    ///
    /// let config = ServerConfig::default();
    /// assert_eq!(config.listen_addr(), "127.0.0.1:8000");
    /// ```
    #[wasm_bindgen(js_name = "listenAddr")]
    pub fn listen_addr(&self) -> String {
        kreuzberg::ServerConfig::from(self.clone()).listen_addr()
    }

    /// Check if CORS allows all origins.
    ///
    /// Returns `true` if the `cors_origins` vector is empty, meaning all origins
    /// are allowed. Returns `false` if specific origins are configured.
    ///
    /// # Example
    ///
    /// ```rust
    /// use kreuzberg::core::ServerConfig;
    ///
    /// let mut config = ServerConfig::default();
    /// assert!(config.cors_allows_all());
    ///
    /// config.cors_origins.push("https://example.com".to_string());
    /// assert!(!config.cors_allows_all());
    /// ```
    #[wasm_bindgen(js_name = "corsAllowsAll")]
    pub fn cors_allows_all(&self) -> bool {
        kreuzberg::ServerConfig::from(self.clone()).cors_allows_all()
    }

    /// Check if a given origin is allowed by CORS configuration.
    ///
    /// Returns `true` if:
    /// - CORS allows all origins (empty origins list), or
    /// - The given origin is in the allowed origins list
    ///
    /// # Arguments
    ///
    /// * `origin` - The origin to check (e.g., "https://example.com")
    ///
    /// # Example
    ///
    /// ```rust
    /// use kreuzberg::core::ServerConfig;
    ///
    /// let mut config = ServerConfig::default();
    /// assert!(config.is_origin_allowed("https://example.com"));
    ///
    /// config.cors_origins.push("https://allowed.com".to_string());
    /// assert!(config.is_origin_allowed("https://allowed.com"));
    /// assert!(!config.is_origin_allowed("https://denied.com"));
    /// ```
    #[wasm_bindgen(js_name = "isOriginAllowed")]
    pub fn is_origin_allowed(&self, origin: String) -> bool {
        kreuzberg::ServerConfig::from(self.clone()).is_origin_allowed(&origin)
    }

    /// Get maximum request body size in megabytes (rounded up).
    ///
    /// # Example
    ///
    /// ```rust
    /// use kreuzberg::core::ServerConfig;
    ///
    /// let mut config = ServerConfig::default();
    /// assert_eq!(config.max_request_body_mb(), 100);
    /// ```
    #[wasm_bindgen(js_name = "maxRequestBodyMb")]
    pub fn max_request_body_mb(&self) -> usize {
        kreuzberg::ServerConfig::from(self.clone()).max_request_body_mb()
    }

    /// Get maximum multipart field size in megabytes (rounded up).
    ///
    /// # Example
    ///
    /// ```rust
