/// Extract content from a byte array.
///
/// This is the main entry point for in-memory extraction. It performs the following steps:
/// 1. Validate MIME type
/// 2. Handle legacy format conversion if needed
/// 3. Select appropriate extractor from registry
/// 4. Extract content
/// 5. Run post-processing pipeline
///
/// # Arguments
///
/// * `content` - The byte array to extract
/// * `mime_type` - MIME type of the content
/// * `config` - Extraction configuration
///
/// # Returns
///
/// An `ExtractionResult` containing the extracted content and metadata.
///
/// # Errors
///
/// Returns `KreuzbergError::Validation` if MIME type is invalid.
/// Returns `KreuzbergError::UnsupportedFormat` if MIME type is not supported.
///
/// # Example
///
/// ```rust,no_run
/// use kreuzberg::core::extractor::extract_bytes;
/// use kreuzberg::core::config::ExtractionConfig;
///
/// # async fn example() -> kreuzberg::Result<()> {
/// let config = ExtractionConfig::default();
/// let bytes = b"Hello, world!";
/// let result = extract_bytes(bytes, "text/plain", &config).await?;
/// println!("Content: {}", result.content);
/// # Ok(())
/// # }
/// ```
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "extractBytes")]
pub async fn extract_bytes(
    content: Vec<u8>,
    mime_type: String,
    config: WasmExtractionConfig,
) -> Result<WasmExtractionResult, JsValue> {
    let config_core: kreuzberg::ExtractionConfig = config.into();
    let result = kreuzberg::extract_bytes(&content, &mime_type, &config_core)
        .await
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(WasmExtractionResult::from(result))
}

/// Extract content from a file.
///
/// This is the main entry point for file-based extraction. It performs the following steps:
/// 1. Check cache for existing result (if caching enabled)
/// 2. Detect or validate MIME type
/// 3. Select appropriate extractor from registry
/// 4. Extract content
/// 5. Run post-processing pipeline
/// 6. Store result in cache (if caching enabled)
///
/// # Arguments
///
/// * `path` - Path to the file to extract
/// * `mime_type` - Optional MIME type override. If None, will be auto-detected
/// * `config` - Extraction configuration
///
/// # Returns
///
/// An `ExtractionResult` containing the extracted content and metadata.
///
/// # Errors
///
/// Returns `KreuzbergError::Io` if the file doesn't exist (NotFound) or for other file I/O errors.
/// Returns `KreuzbergError::UnsupportedFormat` if MIME type is not supported.
///
/// # Example
///
/// ```rust,no_run
/// use kreuzberg::core::extractor::extract_file;
/// use kreuzberg::core::config::ExtractionConfig;
///
/// # async fn example() -> kreuzberg::Result<()> {
/// let config = ExtractionConfig::default();
/// let result = extract_file("document.pdf", None, &config).await?;
/// println!("Content: {}", result.content);
/// # Ok(())
/// # }
/// ```
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "extractFile")]
pub async fn extract_file(
    path: String,
    mime_type: Option<String>,
    config: WasmExtractionConfig,
) -> Result<WasmExtractionResult, JsValue> {
    let config_core: kreuzberg::ExtractionConfig = config.into();
    let result = kreuzberg::extract_file(path, mime_type.as_deref(), &config_core)
        .await
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(WasmExtractionResult::from(result))
}

/// Synchronous wrapper for `extract_file`.
///
/// This is a convenience function that blocks the current thread until extraction completes.
/// For async code, use `extract_file` directly.
///
/// Uses the global Tokio runtime for 100x+ performance improvement over creating
/// a new runtime per call. Always uses the global runtime to avoid nested runtime issues.
///
/// This function is only available with the `tokio-runtime` feature. For WASM targets,
/// use a truly synchronous extraction approach instead.
///
/// # Example
///
/// ```rust,no_run
/// use kreuzberg::core::extractor::extract_file_sync;
/// use kreuzberg::core::config::ExtractionConfig;
///
/// let config = ExtractionConfig::default();
/// let result = extract_file_sync("document.pdf", None, &config)?;
/// println!("Content: {}", result.content);
/// # Ok::<(), kreuzberg::KreuzbergError>(())
/// ```
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "extractFileSync")]
pub fn extract_file_sync(
    path: String,
    mime_type: Option<String>,
    config: JsValue,
) -> Result<WasmExtractionResult, JsValue> {
    let config_core: kreuzberg::ExtractionConfig =
        serde_wasm_bindgen::from_value::<kreuzberg::ExtractionConfig>(config)
            .map_err(|e| JsValue::from_str(&e.to_string()))?;
    let result = kreuzberg::extract_file_sync(path, mime_type.as_deref(), &config_core)
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result.into())
}

