/// Synchronous wrapper for `batch_extract_file`.
///
/// Uses the global Tokio runtime for optimal performance.
/// Only available with `tokio-runtime` (WASM has no filesystem).
///
/// # Example
///
/// ```rust,no_run
/// use kreuzberg::core::extractor::batch_extract_file_sync;
/// use kreuzberg::core::config::ExtractionConfig;
/// use kreuzberg::FileExtractionConfig;
/// use std::path::PathBuf;
///
/// let config = ExtractionConfig::default();
/// let items: Vec<(PathBuf, Option<FileExtractionConfig>)> = vec![
///     ("doc1.pdf".into(), Some(FileExtractionConfig { force_ocr: Some(true), ..Default::default() })),
///     ("doc2.pdf".into(), None),
/// ];
/// let results = batch_extract_file_sync(items, &config)?;
/// # Ok::<(), kreuzberg::KreuzbergError>(())
/// ```
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "batchExtractFileSync")]
pub fn batch_extract_file_sync(items: Vec<String>, config: JsValue) -> Result<Vec<WasmExtractionResult>, JsValue> {
    let items_core: Vec<_> = items
        .into_iter()
        .map(|s| serde_json::from_str(&s).map_err(|e| JsValue::from_str(&e.to_string())))
        .collect::<Result<Vec<_>, _>>()?;
    let config_core: kreuzberg::ExtractionConfig =
        serde_wasm_bindgen::from_value::<kreuzberg::ExtractionConfig>(config)
            .map_err(|e| JsValue::from_str(&e.to_string()))?;
    let result =
        kreuzberg::batch_extract_file_sync(items_core, &config_core).map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result.into_iter().map(Into::into).collect())
}

