/// Split text into chunks with optional page boundary tracking.
///
/// This is the primary API function for chunking text. It supports both plain text
/// and Markdown with configurable chunk size, overlap, and page boundary mapping.
///
/// # Arguments
///
/// * `text` - The text to split into chunks
/// * `config` - Chunking configuration (max size, overlap, type)
/// * `page_boundaries` - Optional page boundary markers for mapping chunks to pages
///
/// # Returns
///
/// A ChunkingResult containing all chunks and their metadata.
///
/// # Examples
///
/// ```rust
/// use kreuzberg::chunking::{chunk_text, ChunkingConfig, ChunkerType};
///
/// # fn example() -> kreuzberg::Result<()> {
/// let config = ChunkingConfig {
///     max_characters: 500,
///     overlap: 50,
///     trim: true,
///     chunker_type: ChunkerType::Text,
///     ..Default::default()
/// };
/// let result = chunk_text("Long text...", &config, None)?;
/// assert!(!result.chunks.is_empty());
/// # Ok(())
/// # }
/// ```
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "chunkText")]
pub fn chunk_text(
    text: String,
    config: JsValue,
    page_boundaries: Option<Vec<String>>,
) -> Result<WasmChunkingResult, JsValue> {
    let config_core: kreuzberg::ChunkingConfig = serde_wasm_bindgen::from_value::<kreuzberg::ChunkingConfig>(config)
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    let page_boundaries_core: Option<Vec<kreuzberg::PageBoundary>> = page_boundaries
        .map(|strings| {
            strings
                .into_iter()
                .map(|s| {
                    serde_json::from_str::<kreuzberg::PageBoundary>(&s).map_err(|e| JsValue::from_str(&e.to_string()))
                })
                .collect::<Result<Vec<_>, _>>()
        })
        .transpose()?;
    let result = kreuzberg::chunking::chunk_text(&text, &config_core, page_boundaries_core.as_deref())
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result.into())
}

/// Chunk text with an optional separate markdown source for heading context resolution.
///
/// When `heading_source` is provided, it is used instead of `text` for building the
/// heading map. This is needed when `text` is plain text (no markdown headings) but
/// the original document had headings that were stripped during rendering.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "chunkTextWithHeadingSource")]
pub fn chunk_text_with_heading_source(
    text: String,
    config: JsValue,
    page_boundaries: Option<Vec<String>>,
    heading_source: Option<String>,
) -> Result<WasmChunkingResult, JsValue> {
    let config_core: kreuzberg::ChunkingConfig = serde_wasm_bindgen::from_value::<kreuzberg::ChunkingConfig>(config)
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    let page_boundaries_core: Option<Vec<kreuzberg::PageBoundary>> = page_boundaries
        .map(|strings| {
            strings
                .into_iter()
                .map(|s| {
                    serde_json::from_str::<kreuzberg::PageBoundary>(&s).map_err(|e| JsValue::from_str(&e.to_string()))
                })
                .collect::<Result<Vec<_>, _>>()
        })
        .transpose()?;
    let result = kreuzberg::chunking::core::chunk_text_with_heading_source(
        &text,
        &config_core,
        page_boundaries_core.as_deref(),
        heading_source.as_deref(),
    )
    .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result.into())
}

/// Split text into semantically coherent chunks.
///
/// Splits text into fine-grained segments, detects structural (and optionally
/// embedding-based) topic boundaries, then merges segments into chunks that
/// respect those boundaries and the configured size budget.
#[allow(clippy::missing_errors_doc)]
#[wasm_bindgen(js_name = "chunkSemantic")]
pub fn chunk_semantic(
    text: String,
    config: JsValue,
    page_boundaries: Option<Vec<String>>,
) -> Result<WasmChunkingResult, JsValue> {
    let config_core: kreuzberg::ChunkingConfig = serde_wasm_bindgen::from_value::<kreuzberg::ChunkingConfig>(config)
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    let page_boundaries_core: Option<Vec<kreuzberg::PageBoundary>> = page_boundaries
        .map(|strings| {
            strings
                .into_iter()
                .map(|s| {
                    serde_json::from_str::<kreuzberg::PageBoundary>(&s).map_err(|e| JsValue::from_str(&e.to_string()))
                })
                .collect::<Result<Vec<_>, _>>()
        })
        .transpose()?;
    let result = kreuzberg::chunking::semantic::chunk_semantic(&text, &config_core, page_boundaries_core.as_deref())
        .map_err(|e| JsValue::from_str(&e.to_string()))?;
    Ok(result.into())
}

